const fs = require('fs');
const config = $('Set Configuration').first().json.config;

// Check file mount and inputs
try {
  if (!fs.existsSync(config.EXCEL_FILE)) {
    throw new Error(`Excel file not found at: ${config.EXCEL_FILE}`);
  }
  if (!fs.existsSync(config.SOURCE_PDF_DIR)) {
    throw new Error(`PDF Source directory not found at: ${config.SOURCE_PDF_DIR}`);
  }

  const files = fs.readdirSync(config.SOURCE_PDF_DIR);

  // Check write permission to log path
  fs.writeFileSync(`${config.LOG_PATH}/.preflight_ok`, new Date().toISOString());

  // Grab categories out of the previous node (Fetch Categories) if available
  // otherwise use fallback array
  let categories = ['Correspondence','RFA','Drawing','Transmittal','Report','Other'];
  try {
    const upstreamData = $('Fetch Categories').first()?.json?.data;
    if (upstreamData && Array.isArray(upstreamData)) {
        categories = upstreamData.map(c => c.name || c.type || c); // very loose mapping depending on API response
    }
  } catch(e) {}

  // Grab existing tags from Fetch Tags node
  let existingTags = [];
  try {
    const tagData = $('Fetch Tags').first()?.json?.data || [];
    existingTags = Array.isArray(tagData) ? tagData.map(t => t.tag_name || t.name || '').filter(Boolean) : [];
  } catch(e) {}

  return [{ json: { 
    preflight_ok: true, 
    pdf_count_in_source: files.length,
    excel_target: config.EXCEL_FILE,
    system_categories: categories,
    existing_tags: existingTags,
    timestamp: new Date().toISOString()
  }}];
} catch (err) {
  throw new Error(`Pre-flight check failed: ${err.message}`);
}

const cpJson = $input.first()?.json || {};
const startIndex = cpJson.last_processed_index || 0;
const config = $('Set Configuration').first().json.config;

const allItems = $('Read Excel').all().map(i => i.json);
const remaining = allItems.slice(startIndex);
const currentBatch = remaining.slice(0, config.BATCH_SIZE);

// Encoding Normalization
const normalize = (str) => {
  if (!str) return '';
  return String(str).normalize('NFC').trim();
};

return currentBatch.map((item, i) => {
  // Safe getter to handle whitespace or case in Excel column names
  const getVal = (possibleKeys) => {
    const exactMatch = possibleKeys.find(k => item[k] !== undefined);
    if (exactMatch) return item[exactMatch];

    // Fallback: Check lowercase/trimmed keys if exact match fails
    const lowerTrimmedKeys = Object.keys(item).map(k => ({ original: k, parsed: k.toLowerCase().trim() }));
    for (const pk of possibleKeys) {
      const found = lowerTrimmedKeys.find(k => k.parsed === pk.toLowerCase().trim());
      if (found) return item[found.original];
    }
    return '';
  };

  const docNum = getVal(['document_number', 'correspondence_number', 'Document Number', 'Corr. No.']);
  const excelFileName = getVal(['File name', 'file_name', 'File Name', 'filename']);

  if (!excelFileName) {
    throw new Error(`Missing 'File name' column for row ${i + startIndex + 1}, document: ${docNum}`);
  }

  return {
    json: {
      document_number: normalize(docNum),
      title: normalize(getVal(['title', 'Title', 'Subject', 'subject'])),
      legacy_number: normalize(getVal(['legacy_number', 'Legacy Number', 'Response Doc.'])),
      excel_revision: getVal(['revision', 'Revision', 'rev']) || 1,
      original_index: startIndex + i,
      batch_id: config.BATCH_ID,
      file_name: normalize(excelFileName),
      issued_date: normalize(getVal(['issued_date', 'Issued_date', 'Issued Date', 'date', 'Date', 'document_date', 'Document_Date'])),
      received_date: normalize(getVal(['received_date', 'Received_date', 'Received Date', 'receive', 'Receive'])),
      correspondence_type: normalize(getVal(['correspondence_types', 'correspondence_type', 'Correspondence Types', 'Correspondence Type'])),
      sender: normalize(getVal(['sender', 'Sender', 'from', 'From'])),
      receiver: normalize(getVal(['receiver', 'Receiver', 'to', 'To'])),
      project_code: normalize(getVal(['project_code', 'Project Code', 'project', 'Project'])),
      _raw_excel_keys: Object.keys(item),
      _raw_excel: item
    }
  };
});

const fs = require('fs');
const path = require('path');
const config = $('Set Configuration').first().json.config;

const items = $input.all();
if (!items || items.length === 0) return [];

const validated = [];
const errors = [];

for (const item of items) {
  const fileName = item.json?.file_name;
  if (!fileName) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: 'file_name is missing', error_type: 'MISSING_FILENAME', file_exists: false }
    });
    continue;
  }

  // Use file name from Excel directly, add .pdf if missing
  let safeName = path.basename(String(fileName)).normalize('NFC');
  if (!safeName.toLowerCase().endsWith('.pdf')) {
    safeName += '.pdf';
  }
  const filePath = path.resolve(config.SOURCE_PDF_DIR, safeName);

  // Path traversal check
  if (!filePath.startsWith(path.resolve(config.SOURCE_PDF_DIR))) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: 'Path traversal detected', error_type: 'SECURITY', file_exists: false }
    });
    continue;
  }

  try {
    if (fs.existsSync(filePath)) {
      const stats = fs.statSync(filePath);
      validated.push({
        ...item,
        json: { ...item.json, file_valid: true, file_exists: true, file_size: stats.size, file_path: filePath }
      });
    } else {
      errors.push({
        ...item,
        json: { ...item.json, file_valid: false, error: `File not found: ${safeName}`, error_type: 'FILE_NOT_FOUND', file_exists: false }
      });
    }
  } catch (err) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: err.message, error_type: 'FILE_ERROR', file_exists: false }
    });
  }
}

return [...validated, ...errors];

const config = $('Set Configuration').first().json.config;
const fallbackState = $('Check Fallback State').first()?.json || { is_fallback_active: false, recent_error_count: 0 };
const isFallback = fallbackState.is_fallback_active || false;
const model = isFallback ? config.OLLAMA_MODEL_FALLBACK : config.OLLAMA_MODEL_PRIMARY;

// Read DB Context
const dbContext = $('Fetch DB Context').all().map(i => i.json);
const dbProjects = dbContext.filter(d => d.type === 'projects').map(d => ({id: d.id, code: d.text1, name: d.text2}));
const dbDisciplines = dbContext.filter(d => d.type === 'disciplines').map(d => ({id: d.id, th: d.text1, en: d.text2}));
const dbOrgs = dbContext.filter(d => d.type === 'organizations').map(d => ({id: d.id, name: d.text1, code: d.text2}));
const dbTags = dbContext.filter(d => d.type === 'tags').map(d => ({id: d.id, name: d.text1}));
const dbCorrTypes = dbContext.filter(d => d.type === 'correspondence_types').map(d => ({id: d.id, code: d.text1, name: d.text2}));

let systemCategories = ['Correspondence','RFA','Drawing','Transmittal','Report','Other'];
try { systemCategories = $('File Mount Check').first().json.system_categories || systemCategories; } catch (e) {}

const pdfItems = $('Extract PDF Text').all();
// File Validator passes all original Excel JSON fields through (sender, receiver, project_code, etc.)
// Read PDF File overwrites the JSON with binary data, so we must go back one step
const metaItems = $('File Validator').all();

return pdfItems.map((pdfItem, i) => {
  const item = metaItems[i] || pdfItem;

  const docNum = String(item.json.document_number || '');
  const title = String(item.json.title || '');
  const legacyNum = String(item.json.legacy_number || '');
  const issuedDate = String(item.json.issued_date || '');
  const receivedDate = String(item.json.received_date || '');
  const corrType = String(item.json.correspondence_type || '');
  const senderCode = String(item.json.sender || '');
  const receiverCode = String(item.json.receiver || '');
  const projectCode = String(item.json.project_code || '');

  // JavaScript pre-mapping
  const findOrgId = (code) => {
    if (!code) return null;
    const match = dbOrgs.find(o => o.code === code || o.name === code);
    return match ? match.id : null;
  };

  const findProjectId = (code) => {
    if (!code) return config.PROJECT_ID; // Fallback to config
    const match = dbProjects.find(p => p.code === code || p.name === code);
    return match ? match.id : config.PROJECT_ID;
  };

  const senderId = findOrgId(senderCode);
  const receiverId = findOrgId(receiverCode);
  const projectId = findProjectId(projectCode);
  // Excel corrType is likely already the ID based on requirements, but fallback matching to ID if needed
  const corrMatch = dbCorrTypes.find(c => String(c.id) === corrType || c.code === corrType || c.name === corrType);
  const corrTypeId = corrMatch ? corrMatch.id : (isNaN(parseInt(corrType)) ? null : parseInt(corrType));

  const isRFA = docNum.includes('-RFA-') || title.toLowerCase().includes('rfa');

  const systemPrompt = `You are an expert Document Controller for a construction project (LCBP3) in Thailand.
The documents are primarily in THAI and ENGLISH.
Your task is to classify documents and extract metadata from OCR text.
Respond ONLY with valid JSON.`;

  // Use pdfItem for the OCR extracted data, NOT the metaItem
  const pdfText = String(pdfItem.json.data || '').substring(0, 3500).replace(/[^a-zA-Z0-9ก-๙\s\.\/\-:\[\]\(\)]/g, ' ');

  const userPrompt = `Analyze this document:
[EXCEL METADATA]
Document Number: ${docNum || 'Not provided'}
Title: ${title || 'Not provided'}
Issued Date: ${issuedDate || 'Not provided'}
Received Date: ${receivedDate || 'Not provided'}

[DATABASE REFERENCES]
Disciplines: ${JSON.stringify(dbDisciplines)}
Tags: ${JSON.stringify(dbTags)}

[OCR TEXT EXTRACTION]
${pdfText}

Rules:
1. Category: Must be one of ${JSON.stringify(systemCategories)}. If Document Number contains "-RFA-", category MUST be "RFA".
2. Respond with EXACTLY 8 fields in JSON format:
   - "discipline_id": Find 'id' from Disciplines array analyzing text to match 'th' or 'en'. If no match, use ID=64 (from contract LCBP3-C2).
   - "subject": Document subject. If OCR is close to EXCEL METADATA Title, use EXCEL METADATA.
   - "issued_date": Verify from OCR text if it matches ${issuedDate}, format YYYY-MM-DD.
   - "received_date": Verify from OCR text. If empty, default to issued_date.
   - "status": Extract status (e.g., For Information, Approve, Reject, Resubmit). This will be exported as "remark".
   - "summary": 4-5 lines of Thai summary from OCR. This will be exported as "body".
   - "tags": REQUIRED. Identify 2-5 main topics/themes from the document (from Title, subject matter, and OCR text). For each topic, return an object with:
     * "tag_name": short topic name in Thai (2-5 words), e.g. "คอนกรีตผสม", "ทดสอบวัสดุ"
     * "description": one sentence in Thai describing this topic (use key point details). e.g. "การทดสอบค่า slump ของคอนกรีตผสมที่หน้างาน"
     Return as: [{"tag_name": "...", "description": "..."}, ...]
   - "key_points": Array of 3-5 string key points extracted from the document (in Thai).

3. IMPORTANT: You MUST REPLACE the 'null' values in the template below with the actual Integer IDs or text you found. DO NOT reply with literal 'null' if you found a match!

Respond ONLY with this EXACT JSON structure:
{
  "discipline_id": 64,
  "subject": "${title}",
  "issued_date": "${issuedDate}",
  "received_date": "${receivedDate || issuedDate}",
  "status": null,
  "summary": "สรุปเนื้อหา 4-5 บรรทัด...",
  "tags": [{"tag_name": "ชื่อหัวข้อ", "description": "คำอธิบาย key point ของหัวข้อนี้"}],
  "key_points": ["จุดสำคัญที่ 1", "จุดสำคัญที่ 2", "จุดสำคัญที่ 3"],
  "category": "${isRFA ? 'RFA' : 'Correspondence'}",
  "confidence": 0.95
}`;

  return {
    json: {
      ...item.json,
      active_model: model,
      is_fallback: isFallback,
      system_categories: systemCategories,
      pre_mapped: {
        project_id: projectId,
        sender_id: senderId,
        receiver_id: receiverId,
        correspondence_type_id: corrTypeId
      },
      _debug_mapping: {
        excel_project_code: projectCode,
        excel_sender: senderCode,
        excel_receiver: receiverCode,
        excel_corr_type: corrType,
        matched_project: dbProjects.find(p => p.code === projectCode || p.name === projectCode) || null,
        first_org_sample: dbOrgs[0] || null
      },
      ollama_payload: {
        model: model,
        prompt: `${systemPrompt}\n\n${userPrompt}`,
        stream: false,
        format: 'json',
        options: {
          temperature: 0.1,
          num_ctx: 8192
        }
      }
    }
  };
});

const ollamaItems = $input.all();
const originalItems = $('Build AI Prompt').all();
const results = [];

// Map AI category names → correspondence_types.type_code in DB
const CATEGORY_TO_TYPE_CODE = {
  'Correspondence': 'LETTER',
  'RFA': 'RFA',
  'Transmittal': 'TRANSMITTAL',
  'Drawing': 'OTHER',
  'Report': 'OTHER',
  'Other': 'OTHER',
};

for (let i = 0; i < ollamaItems.length; i++) {
  const ollamaItem = ollamaItems[i];
  const originalItem = originalItems[i];
  if (!originalItem) continue;
  const baseJson = originalItem.json;

  try {
    let raw = ollamaItem.json.response || '';
    raw = raw.replace(/`{3}json/gi, '').replace(/`{3}/g, '').trim();
    if (!raw) throw new Error('Empty response from AI');

    const result = JSON.parse(raw);

    // Map AI result to database fields
    let tags = Array.isArray(result.tags) ? result.tags : [];

    // Enum Validation for Category
    const systemCategories = baseJson.system_categories || [];
    let finalCategory = result.category;
    if (!systemCategories.includes(finalCategory)) {
      finalCategory = String(baseJson.document_number || '').includes('-RFA-') ? 'RFA' : 'Correspondence';
    }

    // Map to type_code for Backend API
    const typeCode = CATEGORY_TO_TYPE_CODE[finalCategory] || 'LETTER';

    const preMapped = baseJson.pre_mapped || {};

    results.push({
      json: {
        ...baseJson,
        ai_result: {
          suggested_category: finalCategory,
          type_code: typeCode,
          confidence: result.confidence || 0.8,
          project_id: preMapped.project_id || null,
          discipline_id: result.discipline_id || 64,
          sender_id: preMapped.sender_id || null,
          receiver_id: preMapped.receiver_id || null,
          correspondence_type_id: preMapped.correspondence_type_id || null,
          subject: result.subject || baseJson.title,
          issued_date: result.issued_date || baseJson.issued_date,
          received_date: result.received_date || baseJson.received_date || result.issued_date || baseJson.issued_date,
          remark: result.status,
          body: result.summary,
          tags: tags,
          key_points: result.key_points || []
        },
        parse_error: null
      }
    });
  } catch (err) {
    results.push({
      json: {
        ...baseJson,
        ai_result: null,
        parse_error: err.message,
        raw_ai_response: ollamaItem.json.response,
        error_type: 'AI_PARSE_ERROR'
      }
    });
  }
}
return results;

const config = $('Set Configuration').first().json.config;
const items = $('Parse & Validate AI Response').all();

const results = [];

for (const item of items) {
  const data = item.json;

  // Base structure ensuring we keep all existing data
  let resultItem = { json: { ...data } };

  // Handle Parse Errors from upstream
  if (data.parse_error || !data.ai_result) {
    resultItem.json.route_index = 3;
    results.push(resultItem);
    continue;
  }

  const ai = data.ai_result;

  // Revision Drift Protection
  if (data.current_db_revision !== undefined) {
    const expectedRev = data.current_db_revision + 1;
    if (parseInt(data.excel_revision) !== expectedRev) {
      resultItem.json.review_reason = `Revision drift: Excel=${data.excel_revision}, Expected=${expectedRev}`;
      resultItem.json.route_index = 1;
      results.push(resultItem);
      continue;
    }
  }

  // Confidence Routing
  if (ai.confidence >= config.CONFIDENCE_HIGH) {
    resultItem.json.route_index = 0;
  } else if (ai.confidence >= config.CONFIDENCE_LOW) {
    resultItem.json.review_reason = `Confidence ${ai.confidence.toFixed(2)} < ${config.CONFIDENCE_HIGH}`;
    resultItem.json.route_index = 1;
  } else {
    resultItem.json.reject_reason = ai.is_valid === false ? 'AI marked invalid' : `Confidence ${ai.confidence.toFixed(2)} < ${config.CONFIDENCE_LOW}`;
    resultItem.json.route_index = 2;
  }
  results.push(resultItem);
}

return results;

// $input here is the HTTP response from Import to Backend — it has no original_index.
// We must go back to Build Import Payload which preserved the original item data.
const originalData = $('Build Import Payload').first().json;
const importResponse = $input.first().json;

const idx = originalData.original_index ?? 0;
const shouldCheckpoint = idx % 10 === 0;

return [{
  json: {
    ...originalData,
    import_response: importResponse,
    should_update_checkpoint: shouldCheckpoint,
    checkpoint_index: idx,
    import_status: 'success',
    timestamp: new Date().toISOString()
  }
}];

const fs = require('fs');
const item = $input.first();
const config = $('Set Configuration').first().json.config;

const csvPath = `${config.LOG_PATH}/reject_log.csv`;
const header = 'timestamp,document_number,title,reject_reason,ai_confidence,key_points\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

const line = [
  new Date().toISOString(),
  esc(item.json.document_number),
  esc(item.json.title),
  esc(item.json.reject_reason),
  item.json.ai_result?.confidence ?? 'N/A',
  esc(JSON.stringify(item.json.ai_result?.key_points || []))
].join(',') + '\n';

fs.appendFileSync(csvPath, line, 'utf8');

return [$input.first()];

const fs = require('fs');
const items = $input.all();
const config = $('Set Configuration').first().json.config;

const csvPath = `${config.LOG_PATH}/error_log.csv`;
const header = 'timestamp,document_number,error_type,error_message,raw_ai_response\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

for (const item of items) {
  const line = [
    new Date().toISOString(),
    esc(item.json.document_number),
    esc(item.json.error_type || 'UNKNOWN'),
    esc(item.json.error || item.json.parse_error),
    esc(item.json.raw_ai_response || '')
  ].join(',') + '\n';

  fs.appendFileSync(csvPath, line, 'utf8');
}

return items;

const item = $input.first();
const config = $('Set Configuration').first().json.config;
const ai = item.json.ai_result || {};

return [{
  json: {
    ...item.json,
    import_payload: {
      document_number: String(item.json.document_number || ''),
      title: String(ai.subject || item.json.title || 'ไม่มีชื่อเรื่อง'),
      category: ai.type_code || 'LETTER',
      source_file_path: item.json.file_path || '/dev/null',
      ai_confidence: ai.confidence || 0.8,
      migrated_by: 'SYSTEM_IMPORT',
      batch_id: config.BATCH_ID,
      project_id: Number(ai.project_id || config.PROJECT_ID),
      issued_date: ai.issued_date || '',
      received_date: ai.received_date || '',
      body: ai.body || '',
      details: {
        legacy_number: item.json.legacy_number || '',
        remark: ai.remark || '',
        key_points: ai.key_points || [],
        tags: ai.tags || []
      }
    }
  }
}];

const item = $input.first().json;
const config = $('Set Configuration').first().json.config;
const tags = item.import_payload?.details?.tags || item.ai_result?.tags || [];
const projectId = item.import_payload?.project_id || item.ai_result?.project_id || config.PROJECT_ID;

const correspondenceId = item.import_response?.id || item.import_response?.data?.id;

if (!correspondenceId || !Array.isArray(tags) || tags.length === 0) {
  return [{ json: { ...item, tags_upserted: 0, tags_linked: 0, tag_ids_to_link: [], correspondence_id: correspondenceId } }];
}

const results = [];
const tagIds = [];

for (const tag of tags) {
  if (!tag || !tag.tag_name) continue;
  try {
    const response = await $helpers.httpRequest({
      method: 'POST',
      url: `${config.BACKEND_URL}/api/master/tags`,
      headers: {
        'Authorization': config.MIGRATION_TOKEN,
        'Content-Type': 'application/json'
      },
      body: {
        tag_name: String(tag.tag_name),
        description: String(tag.description || ''),
        project_id: Number(projectId),
        color_code: 'default'
      },
      json: true
    });

    if (response && response.id) {
       tagIds.push(response.id);
       results.push({ tag_name: tag.tag_name, status: 'ok', id: response.id });
    }
  } catch (e) {
    try {
        const searchRes = await $helpers.httpRequest({
            method: 'GET',
            url: `${config.BACKEND_URL}/api/master/tags?project_id=${projectId}&search=${encodeURIComponent(tag.tag_name)}`,
            headers: {
                'Authorization': config.MIGRATION_TOKEN
            },
            json: true
        });

        const existing = searchRes.data?.find(t => t.tag_name === tag.tag_name);
        if (existing && existing.id) {
             tagIds.push( existing.id );
             results.push({ tag_name: tag.tag_name, status: 'found_existing', id: existing.id });
        } else {
             results.push({ tag_name: tag.tag_name, status: 'error_conflict_not_found', reason: String(e.message || e) });
        }
    } catch(fetchErr) {
        results.push({ tag_name: tag.tag_name, status: 'error_fetching_existing', reason: String(fetchErr.message || fetchErr) });
    }
  }
}

return [{ 
    json: { 
        ...item, 
        tags_upserted: results.filter(r => r.status === 'ok').length,
        tag_ids_to_link: tagIds,
        correspondence_id: correspondenceId,
        tags_result: results
    } 
}];
